import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { api, ApiError, type TikTokInsightsResponse } from '../../../services/api';

export default function TikTokDetail() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const [data, setData] = useState<TikTokInsightsResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [notConnected, setNotConnected] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setNotConnected(false);
        const insights = await api.getTikTokInsights();
        setData(insights);
      } catch (err) {
        console.error('Failed to fetch TikTok insights:', err);
        if (err instanceof ApiError && (err.status === 404 || err.status === 422)) {
          setNotConnected(true);
        } else {
          setNotConnected(true);
        }
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (!loading && notConnected) {
    return (
      <div className="mb-12">
        <div className="flex items-center space-x-3 mb-6">
          <div className="w-9 h-9 flex items-center justify-center rounded-lg bg-black">
            <i className="ri-tiktok-line text-lg text-white"></i>
          </div>
          <div>
            <h2 className="text-base font-semibold text-gray-800">TikTok</h2>
            <p className="text-xs text-gray-400">{t('tiktok.subtitle')}</p>
          </div>
        </div>
        <div className="bg-white rounded-xl border border-gray-100 p-12">
          <div className="max-w-sm mx-auto text-center">
            <div className="w-16 h-16 mx-auto mb-5 rounded-full bg-gray-100 flex items-center justify-center">
              <i className="ri-tiktok-line text-3xl text-gray-800"></i>
            </div>
            <h3 className="text-lg font-semibold text-gray-900 mb-2">
              {t('tiktok.connectPrompt')}
            </h3>
            <p className="text-sm text-gray-500 mb-6">
              {t('tiktok.connectDesc')}
            </p>
            <button
              onClick={() => navigate('/settings')}
              className="inline-flex items-center px-5 py-2.5 bg-gray-900 text-white text-sm font-medium rounded-lg hover:bg-gray-800 transition-all cursor-pointer"
            >
              <i className="ri-link mr-2"></i>
              {t('dashboard.connectOnSettings')}
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="mb-12">
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center space-x-3">
          <div className="w-9 h-9 flex items-center justify-center rounded-lg bg-black">
            <i className="ri-tiktok-line text-lg text-white"></i>
          </div>
          <div>
            <h2 className="text-base font-semibold text-gray-800">TikTok</h2>
            <p className="text-xs text-gray-400">{t('tiktok.subtitle')}</p>
          </div>
        </div>
      </div>

      {loading && (
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-8 text-center">
          <i className="ri-loader-4-line animate-spin text-3xl text-gray-400 mb-2"></i>
          <p className="text-sm text-gray-500">{t('dashboard.loading')}</p>
        </div>
      )}

      {!loading && data && (
        <>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-5">
            <div className="bg-white rounded-xl border border-gray-100 p-5">
              <div className="flex items-center space-x-2 mb-2">
                <i className="ri-video-line text-gray-400"></i>
                <span className="text-xs text-gray-500">{t('tiktok.videos')}</span>
              </div>
              <p className="text-xl font-semibold text-gray-900">
                {data.account?.videoCount?.toLocaleString() || 0}
              </p>
            </div>
            <div className="bg-white rounded-xl border border-gray-100 p-5">
              <div className="flex items-center space-x-2 mb-2">
                <i className="ri-heart-line text-gray-400"></i>
                <span className="text-xs text-gray-500">{t('tiktok.totalLikes')}</span>
              </div>
              <p className="text-xl font-semibold text-gray-900">
                {data.summary?.totalLikes?.toLocaleString() || 0}
              </p>
            </div>
            <div className="bg-white rounded-xl border border-gray-100 p-5">
              <div className="flex items-center space-x-2 mb-2">
                <i className="ri-eye-line text-gray-400"></i>
                <span className="text-xs text-gray-500">{t('tiktok.avgViews')}</span>
              </div>
              <p className="text-xl font-semibold text-gray-900">
                {data.videos && data.videos.length > 0
                  ? Math.round(data.videos.reduce((sum, v) => sum + v.views, 0) / data.videos.length).toLocaleString()
                  : 0}
              </p>
            </div>
          </div>

          {data.videos && data.videos.length > 0 && (
            <div className="bg-white rounded-xl border border-gray-100 p-5 mb-5">
              <h3 className="text-sm font-semibold text-gray-800 mb-4">{t('tiktok.recentVideos')}</h3>
              <div className="space-y-3">
                {data.videos.slice(0, 5).map((video, index) => (
                  <div key={video.id || index} className="flex items-center space-x-4 p-3 bg-gray-50 rounded-lg">
                    {video.coverUrl ? (
                      <img src={video.coverUrl} alt={video.title || t('tiktok.untitled')} className="w-16 h-16 object-cover rounded-lg" />
                    ) : (
                      <div className="w-16 h-16 bg-gray-200 rounded-lg flex items-center justify-center">
                        <i className="ri-video-line text-gray-400 text-xl"></i>
                      </div>
                    )}
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium text-gray-900 truncate">{video.title || t('tiktok.untitled')}</p>
                      <p className="text-xs text-gray-400">{video.createTime ? new Date(video.createTime * 1000).toLocaleDateString() : ''}</p>
                    </div>
                    <div className="flex items-center space-x-4 text-xs text-gray-500">
                      <span className="flex items-center space-x-1"><i className="ri-eye-line"></i><span>{video.views?.toLocaleString() || 0}</span></span>
                      <span className="flex items-center space-x-1"><i className="ri-heart-line"></i><span>{video.likes?.toLocaleString() || 0}</span></span>
                      <span className="flex items-center space-x-1"><i className="ri-chat-1-line"></i><span>{video.comments?.toLocaleString() || 0}</span></span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div className="bg-white rounded-xl border border-gray-100 p-5">
            <h3 className="text-sm font-semibold text-gray-800 mb-2">{t('tiktok.engagementRate')}</h3>
            <p className="text-xs text-gray-500 mb-4">{t('tiktok.engagementDesc')}</p>
            <div className="text-3xl font-bold text-gray-900">{data.summary?.avgEngagementRate?.toFixed(2) || '0.00'}%</div>
          </div>
        </>
      )}
    </div>
  );
}